function buildTopNav(){document.getElementById("top-nav").innerHTML=`<nav><a href="#home">Home</a><a href="#admin">Admin</a><a href="#categorie">Categorie</a></nav>`}function getRoleBadgeClass(e){return{admin:"badge-blue",responsabile:"badge-purple",dirigente:"badge-green",allenatore:"badge-gold",professionista:"badge-teal"}[e]||"badge-gray"}const S={activeSeason:null};function getActiveSeason(){return{id:"2024-2025"}}function ensureActiveSeason(){if(!S.activeSeason){const e=getActiveSeason();S.activeSeason=e?e.id:""}}const baseAllowed=["view-dashboard","view-users","view-categories"],presidentAllowed=[...baseAllowed],segretarioAllowed=[...baseAllowed,"edit-users","edit-categories"],viewBuilders={ "admin-overview":()=>{document.getElementById("content").innerHTML=`<h1>Admin Overview</h1><p>Stagione attiva: ${S.activeSeason}</p>`},"category-home":()=>{document.getElementById("content").innerHTML=`<h1>Categorie</h1><p>Stagione attiva: ${S.activeSeason}</p>`}};function showView(e){viewBuilders[e]&&viewBuilders[e]()}ensureActiveSeason(),buildTopNav(),showView("admin-overview");
